class ThreadPool {
public:
    ThreadPool(size_t thread_count) : stop_flag(false) {
        for (size_t i = 0; i < thread_count; ++i) {
            threads.emplace_back([this]() {
                while (!stop_flag) {
                    std::unique_lock<std::mutex> lock(mutex);
                    if (stop_flag) {
                        lock.unlock();
                        break;
                    }
                    // Wait for a task to be available
                    condition_variable::wait(lock, [this]() { return stop_flag || !task_queue.empty(); });
                    if (stop_flag) {
                        return;
                    }
                    // Execute the task
                    auto task = task_queue.front();
                    task_queue.pop_front();
                    lock.unlock();
                    std::thread task_thread(task);
                    task_thread.join();
                }
            });
        }
    }

    ~ThreadPool() {
        {
            std::unique_lock<std::mutex> lock(mutex);
            stop_flag = true;
        }
        condition_variable::notify_all();
        for (auto& thread : threads) {
            thread.join();
        }
    }

    template <typename Func, typename... Args>
    auto addTask(Func func, Args... args) -> std::future<std::future_result_t<Func, Args...>> {
        using Result = std::future_result_t<Func, Args...>;
        std::future<Result> future = std::make_future<Result>();
        std::packaged_task<Func(Args...)> task(func);
        std::future<std::future_result_t<Func, Args...>> res = task.get_future();
        {
            std::unique_lock<std::mutex> lock(mutex);
            task_queue.push_back(std::move(task));
        }
        condition_variable::notify_one();
        return res;
    }

    void shutdownNow() {
        {
            std::unique_lock<std::mutex> lock(mutex);
            stop_flag = true;
        }
        condition_variable::notify_all();
    }

private:
    std::vector<std::thread> threads;
    std::queue<std::packaged_task<void()>> task_queue;
    std::mutex mutex;
    std::condition_variable condition_variable;
    bool stop_flag;
};

