// FileReader is a struct for reading large files efficiently.
type FileReader struct {
	file        *os.File
	reader      *bytes.Reader
	encoding    string
	buffer      []byte
	readIndex  int
}

// NewFileReader creates a new FileReader for the given file.
func NewFileReader(path string) (*FileReader, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	return &FileReader{
		file:        file,
		reader:      bytes.NewReader([]byte{}),
		encoding:    "",
		buffer:      make([]byte, 4096),
		readIndex:   0,
	}, nil
}

// ReadAllLines reads all lines from the file, streaming content with buffer management and encoding detection.
func (f *FileReader) ReadAllLines() ([]string, error) {
	var lines []string
	var err error

	for {
		// Read a chunk of data
		n, err := f.reader.Read(f.buffer)
		if err != nil {
			return nil, err
		}

		// Check for EOF
		if n == 0 {
			break
		}

		// Process the chunk
		processed, err := f.processChunk(f.buffer[:n])
		if err != nil {
			return nil, err
		}

		lines = append(lines, processed...)
	}

	return lines, nil
}

// processChunk processes a chunk of data and returns the lines and error.
func (f *FileReader) processChunk(data []byte) ([][]byte, error) {
	var lines [][]byte
	var err error

	// Detect encoding
	encoding, err := detectEncoding(data)
	if err != nil {
