    use std::f64;

    pub struct Circle {
        pub radius: f64,
    }

    impl Circle {
        pub fn new(radius: f64) -> Self {
            if radius <= 0.0 {
                panic!("Radius must be positive");
            }
            Circle { radius }
        }

        pub fn calculate_area(&self) -> f64 {
            const PI: f64 = 3.141592653589793;
            PI * self.radius * self.radius
        }

        pub fn set_radius(&mut self, radius: f64) {
            if radius <= 0.0 {
                panic!("Radius must be positive");
            }
            self.radius = radius;
        }
    }

    impl Circle {
        pub fn collides_with(&self, other: &Circle) -> bool {
            let dx = self.radius + other.radius;
            let dy = self.radius + other.radius;
            dx * dx + dy * dy <= (self.radius + other.radius).sqrt() * 2.0
        }
    }
}
