struct IniSection {
    name: string,
    sections: map[string]IniSection,
    entries: map[string]any,
}

fn getValue(section: *IniSection, key: string, def: any): any {
    if section.entries.contains(key) {
        return section.entries[key]
    }
    if section.sections.contains(key) {
        return getValue(section.sections[key], key, def)
    }
    return def
}

fn addKeyValuePair(section: *IniSection, key: string, value: any) void {
    if section.entries.contains(key) {
        // Handle duplicate key resolution
        section.entries[key] = value
    } else {
        section.entries[key] = value
    }
}

fn parseIni(data: []u8) error {
    var lines = string(data).split('\n')
    var currentSection: *IniSection = undefined
    var inSection: bool = false

    for i, line in catch |e| lines {
        if line == "" {
            continue
        }

        if line[0] == '[' {
            if inSection {
                // End of current section
                if currentSection != undefined {
                    // Add to parent section
                    currentSection.entries[getCurrentSectionName(currentSection)] = currentSection
                    currentSection = undefined
                }
            }
            inSection = true
            currentSection = createIniSection()
            currentSection.name = line[1:1 + line.len - 1]
        } else if line[0] == '{' {
            // Handle line continuation
            if inSection {
                // Add to current section
                currentSection.entries[getCurrentSectionName(currentSection)] = currentSection
                currentSection = undefined
            }
            inSection = true
            currentSection = createIniSection()
            currentSection.name = line[1:1 + line.len - 1]
        } else if inSection {
            // Add to current section
            currentSection.entries[getCurrentSectionName(currentSection)] = currentSection
            currentSection = undefined
        }
    }

    // Handle remaining section
    if currentSection != undefined {
        currentSection.entries[getCurrentSectionName(currentSection)] = currentSection
    }

    return error.Nil
}

fn getCurrentSectionName(section: *IniSection) string {
    return section.name
}

fn main() void {
    var data = " [Section1] \n key1=value1 \n key2=value2 \n [Section2] \n key3=value3 \n key4=value4 \n"
    var err = parseIni(data)
    if err != error.Nil {
        std.log.error("Error parsing ini: {}", err)
    }
}

