type PacketDecoder struct {
	packet       *Packet
	header       *Header
	udpHeader    *UDPHeader
	tcpHeader    *TCPHeader
	ipv4Header   *IPv4Header
	ipv6Header   *IPv6Header
	ipv4Data     *[]byte
	ipv6Data     *[]byte
	udpData      *[]byte
	tcpData      *[]byte
	crc32        uint32
	checksum    uint32
}

func (d *PacketDecoder) readHeader() error {
	if d.packet == nil {
		return errors.New("packet is nil")
	}

	if d.header == nil {
		d.header = &Header{}
	}

	if d.udpHeader == nil {
		d.udpHeader = &UDPHeader{}
	}

	if d.tcpHeader == nil {
		d.tcpHeader = &TCPHeader{}
	}

	if d.ipv4Header == nil {
		d.ipv4Header = &IPv4Header{}
	}

	if d.ipv6Header == nil {
		d.ipv6Header = &IPv6Header{}
	}

	// Read IPv4 header
	if err := d.readIPv4Header(); err != nil {
		return err
	}

	// Read UDP header
	if err := d.readUDPHeader(); err != nil {
		return err
	}

	// Read TCP header
	if err := d.readTCPHeader(); err != nil {
		return err
	}

	// Read IP data
	if err := d.readIPData(); err != nil {
		return err
	}

	// Read UDP data
	if err := d.readUDPData(); err != nil {
		return err
	}

	// Read TCP data
	if err := d.readTCPData(); err != nil {
		return err
	}

	return nil
}

func (d *PacketDecoder) readIPv4Header() error {
	// Read IPv4 header
	if d.packet.Data == nil {
		return errors.New("packet data is nil")
	}

	// Read IPv4 header
	if len(d.packet.Data) < 20 {
		return errors.New("packet is too small for IPv4 header")
	}

	// Extract IPv4 header
	header := d.packet.Data[0:20]
	d.ipv4Header = &IPv4Header{
		Version:   header[0],
		HeaderLength: header[1],
		TotalLength: header[2] << 8 | header[3],
		Identification: header[4] << 24 | header[5] << 16 | header[6] << 8 | header[7],
		Flags:      header[8],
		FragmentOffset: header[9] << 24 | header[10] << 16 | header[11] << 8 | header[12],
		TTL:        header[13],
		Protocol:   header[14],
		HeaderCheckSum: header[15],
	}
	return nil
}

func (d *PacketDecoder) readUDPHeader() error {
	// Read UDP header
	if d.packet.Data == nil {
		return errors.New("packet data is nil")
	}

	// Read UDP header
	if len(d.packet.Data) < 8 {
		return errors.New("packet is too small for UDP header")
	}

	// Extract UDP header
	header := d.packet.Data[0:8]
	d.udpHeader = &UDPHeader{
		SourcePort:   header[0] << 24 | header[1] << 16 | header[2] << 8 | header[3],
		DestinationPort: header[4] << 24 | header[5] << 16 | header[6] << 8 | header[7],
		Length:       header[8] << 24 | header[9] << 16 | header[10] << 8 | header[11],
		CheckSum:     header[12] << 24 | header[13] << 16 | header[14] << 8 | header[15],
	}
	return nil
}

func (d *PacketDecoder) readTCPHeader() error {
	// Read TCP header
	if d.packet.Data == nil {
		return errors.New("packet data is nil")
	}

	// Read TCP header
	if len(d.packet.Data) < 20 {
		return errors.New("packet is too small for TCP header")
	}

	// Extract TCP header
	header := d.packet.Data[0:20]
	d.tcpHeader = &TCPHeader{
		SourcePort:   header[0] << 24 | header[1] << 16 | header[2] << 8 | header[3],
		DestinationPort: header[4] << 24 | header[5] << 16 | header[6] << 8 | header[7],
		SequenceNumber: header[8] << 24 | header[9] << 16 | header[10] << 8 | header[11],
		AcknowledgmentNumber: header[12] << 24 | header[13] << 16 | header[14] << 8 | header[15],
		Flags:        header[16],
		Window:       header[17] << 24 | header[18] << 16 | header[19] << 8 | header[20],
	}
	return nil
}

func (d *PacketDecoder) readIPData() error {
	// Read IP data
	if d.packet.Data == nil {
		return errors.New("packet data is nil")
	}

	// Read IP data
	if len(d.packet.Data) < 20 {
		return errors.New("packet is too small for IP data")
	}

	// Extract IP data
	d.ipv4Data = &d.packet.Data[20:]
	return nil
}

func (d *PacketDecoder) readUDPData() error {
	// Read UDP data
	if d.packet.Data == nil {
		return errors.New("packet data is nil")
	}

	// Read UDP data
	if len(d.packet.Data) < 8 {
		return errors.New("packet is too small for UDP data")
	}

	// Extract UDP data
	d.udpData = &d.packet.Data[8:]
	return nil
}

func (d *PacketDecoder) readTCPData() error {
	// Read TCP data
	if d.packet.Data == nil {
		return errors.New("packet data is nil")
	}

	// Read TCP data
	if len(d.packet.Data) < 20 {
		return errors.New("packet is too small for TCP data")
	}

	// Extract TCP data
	d.tcpData = &d.packet.Data[20:]
	return nil
}

func (d *PacketDecoder) validateChecksum() error {
	// Validate CRC-32 checksum
	if d.packet == nil {
		return errors.New("packet is nil")
	}

	// Validate IPv4 header checksum
	if d.ipv4Header != nil {
		if d.ipv4Header.HeaderCheckSum != d.calculateCRC32(d.ipv4Header) {
			return errors.New("invalid IPv4 header checksum")
		}
	}

	// Validate UDP header checksum
	if d.udpHeader != nil {
		if d.udpHeader.CheckSum != d.calculateCRC32(d.udpHeader) {
			return errors.New("invalid UDP header checksum")
		}
	}

	// Validate TCP header checksum
	if d.tcpHeader != nil {
		if d.tcpHeader.CheckSum != d.calculateCRC32(d.tcpHeader) {
			return errors.New("invalid TCP header checksum")
		}
	}

	return nil
}

func (d *PacketDecoder) calculateCRC32(data []byte) uint32 {
	// CRC-32 calculation
	crc := uint32(0)
	for _, b := range data {
		crc = (crc << 8) ^ uint32(b)
	}
	return crc
}

