    fn decode_protocol(&self, packet: &Packet) -> Result<DecodedProtocol, String> {
        self.decoder.decode(packet)
    }

    fn detect_anomaly(&self, packet: &Packet) -> Result<AnomalyResult, String> {
        self.anomaly_detector.detect(packet)
    }

    fn parse_payload(&self, packet: &Packet) -> Result<ParsedPayload, String> {
        self.parser.parse(packet)
    }

    fn aggregate_stats(&self, stats: &mut Stats) {
        self.stats.lock().unwrap().aggregate(stats)
    }

    fn is_ipv4_supported(&self) -> bool {
        self.ipv4_support
    }

    fn is_ipv6_supported(&self) -> bool {
        self.ipv6_support
    }

    fn is_arrow_supported(&self) -> bool {
        self.arrow_serializer.is_supported()
    }
}

