class WebSocketManager {
  constructor(config) {
    this.config = config;
    this.socket = null;
    this.subscribers = new Map();
    this.heartbeatInterval = 30000;
    this.reconnectInterval = 1000;
    this.reconnectJitter = 0;
    this.reconnectAttempts = 0;
    this.isReconnecting = false;
    this.isOnline = false;
  }

  connect() {
    if (this.isReconnecting || !this.isOnline) return;
    this.isReconnecting = true;
    this.reconnectAttempts++;
    this.reconnectInterval = Math.max(this.reconnectInterval * 2, 1000);
    this.reconnectJitter = Math.random() * this.reconnectInterval;
    setTimeout(() => {
      this.socket = new WebSocket(this.config.url);
      this.socket.onopen = this.onSocketOpen.bind(this);
      this.socket.onmessage = this.onMessage.bind(this);
      this.socket.onclose = this.onSocketClose.bind(this);
      this.socket.onerror = this.onSocketError.bind(this);
      this.isOnline = true;
    }, this.reconnectInterval + this.reconnectJitter);
  }

  disconnect() {
    if (this.socket) {
      this.socket.close();
      this.isOnline = false;
    }
  }

  onSocketOpen() {
    this.isOnline = true;
    this.startHeartbeat();
  }

  startHeartbeat() {
    this.heartbeatInterval = 30000;
    this.heartbeatInterval = Math.min(this.heartbeatInterval, 60000);
    this.heartbeatInterval = Math.max(this.heartbeatInterval, 10000);
    this.heartbeatInterval = Math.floor(this.heartbeatInterval / 2);
    setInterval(() => {
      if (this.isOnline) {
        this.socket.send(JSON.stringify({ type: 'heartbeat' }));
      }
    }, this.heartbeatInterval);
  }

  onSocketClose() {
    this.isOnline = false;
    this.isReconnecting = false;
    this.reconnectAttempts = 0;
    this.reconnectInterval = 1000;
    this.reconnectJitter = 0;
  }

  onSocketError(error) {
    this.isOnline = false;
    this.isReconnecting = false;
    this.reconnectAttempts = 0;
    this.reconnectInterval = 1000;
    this.reconnectJitter = 0;
    this.logError(error);
  }

  logError(error) {
    console.error('WebSocket error:', error);
  }

  onMessage(data) {
    try {
      const message = JSON.parse(data);
      if (message.type === 'subscribe') {
        this.subscribeToMarketData(message);
      } else if (message.type === 'unsubscribe') {
        this.unsubscribeFromMarketData(message);
      } else if (message.type === 'update') {
        this.handleMarketDataUpdate(message);
      }
    } catch (e) {
      console.error('Error parsing message:', e);
    }
  }

  subscribeToMarketData(subscription) {
    if (!this.subscribers.has(subscription.channel)) {
      this.subscribers.set(subscription.channel, []);
    }
    this.subscribers.get(subscription.channel).push(subscription);
  }

  unsubscribeFromMarketData(subscription) {
    if (this.subscribers.has(subscription.channel)) {
      this.subscribers.get(subscription.channel) = this.subscribers.get(subscription.channel).filter(s => s !== subscription);
    }
  }

  handleMarketDataUpdate(update) {
    const subscribers = this.subscribers.get(update.channel);
    if (subscribers) {
      subscribers.forEach(sub => {
        sub.onUpdate(update);
      });
    }
  }

  addSubscriber(channel, subscriber) {
    if (!this.subscribers.has(channel)) {
      this.subscribers.set(channel, []);
    }
    this.subscribers.get(channel).push(subscriber);
  }

  removeSubscriber(channel, subscriber) {
    if (this.subscribers.has(channel)) {
      this.subscribers.get(channel) = this.subscribers.get(channel).filter(s => s !== subscriber);
    }
  }

  getSubscribers(channel) {
    return this.subscribers.get(channel) || [];
  }

  // Protocol Buffers message compression
  compressMessage(data) {
    return JSON.stringify(data);
  }

  decompressMessage(compressedData) {
    try {
      return JSON.parse(compressedData);
    } catch (e) {
      console.error('Error decompressing message:', e);
      return null;
    }
  }

  // JSON Schema validation
  validateMessage(data) {
    const schema = {
      type: 'object',
      properties: {
        type: { type: 'string' },
        channel: { type: 'string' },
        payload: { type: 'object' }
      },
      required: ['type', 'channel', 'payload']
    };
    return JSONSchema.validate(data, schema);
  }
}

