	"github.com/aws/aws-sdk-go/service/s3client"
	"github.com/aws/aws-sdk-go/aws/session"
	"github.com/aws/aws-sdk-go/service/s3client"
)

// LogEntry represents a log entry with metadata
type LogEntry struct {
	TimeStamp   time.Time
	Level       string
	Message     string
	Source      string
	Attributes  map[string]string
}

// LogAggregator manages log ingestion, filtering, and storage
type LogAggregator struct {
	// Configuration
	StorageBucket string
	MaxFileSize   int64
	MaxAge         time.Duration
	SSL           bool

	// Internal state
	entries     []LogEntry
	ingestionCh chan *LogEntry
	workerCh    chan *LogEntry
	workers     chan bool
	workerMutex sync.Mutex
	storageMutex sync.Mutex
	// Log rotation
	rotationChan chan bool
	rotationDone bool
	rotationCount int
}

// NewLogAggregator creates a new LogAggregator instance
func NewLogAggregator(config Config) *LogAggregator {
	return &LogAggregator{
		StorageBucket: config.StorageBucket,
		MaxFileSize:   config.MaxFileSize,
		MaxAge:         config.MaxAge,
		SSL:            config.SSL,
	}
}

// Config represents the configuration for the LogAggregator
type Config struct {
	StorageBucket string
	MaxFileSize   int64
	MaxAge         time.Duration
	SSL           bool
}

// LogIngestion handles log ingestion
func (ag *LogAggregator) LogIngestion(logEntry *LogEntry) {
	ag.ingestionCh <- logEntry
}

// ProcessLogs processes incoming log entries
func (ag *LogAggregator) ProcessLogs() {
	// Start a worker to process logs
	go func() {
		for {
			select {
			case logEntry := <-ag.ingestionCh:
				ag.processLog(logEntry)
			case <-ag.rotationChan:
				ag.rotateLogs()
			}
		}
	}()
}

// processLog handles a single log entry
func (ag *LogAggregator) processLog(logEntry *LogEntry) {
	// Apply real-time filtering using regex
	if ag.filterLog(logEntry) {
		ag.entries = append(ag.entries, *logEntry)
		ag.workerMutex.Lock()
		ag.workerMutex.Unlock()
		ag.storageMutex.Lock()
		ag.storageMutex.Unlock()
		ag.rotateLogs()
	}
}

// filterLog applies real-time filtering using regex
func (ag *LogAggregator) filterLog(logEntry *LogEntry) bool {
	// Regular expression for filtering
	re := regexp.MustCompile(`^ERROR`)
	if re.MatchString(logEntry.Message) {
		return true
	}
	return false
}

// rotateLogs performs log rotation based on size and time
func (ag *LogAggregator) rotateLogs() {
	// Check if rotation is needed
	if ag.rotationDone {
		return
	}

	// Get current time
	now := time.Now()

	// Sort logs by time
	ag.entries = ag.entries[:0]
	sort.Slice(ag.entries, func(i, j int) bool {
		return ag.entries[i].TimeStamp.Before(ag.entries[j].TimeStamp)
	})

	// Check if rotation is needed based on size and time
	rotationNeeded := false
	if len(ag.entries) > 0 {
		// Check if size exceeds max file size
		if len(ag.entries) > ag.MaxFileSize {
			rotationNeeded = true
		}
		// Check if age exceeds max age
		if now.Sub(ag.entries[0].TimeStamp) > ag.MaxAge {
			rotationNeeded = true
		}
	}

	if rotationNeeded {
		ag.rotationChan <- true
		ag.rotationDone = true
		ag.rotationCount++
	}
}

// ExportToS3 exports logs to S3
func (ag *LogAggregator) ExportToS3() {
	// Check if storage is enabled
	if ag.StorageBucket == "" {
		return
	}

	// Create S3 client
	sess, err := session.NewSession(&aws.Config{
		Region:      aws.String("us-west-2"),
		Endpoint:    aws.String("https://s3.us-west-2.amazonaws.com"),
		Credentials: credentials.NewEnvProvider(),
		SSL:         aws.Bool(ag.SSL),
	})
	if err != nil {
		log.Fatal(err)
	}

	// Create S3 client
	client := s3.New(sess)

	// Create a directory in S3
	dir := filepath.Join(ag.StorageBucket, "logs", fmt.Sprintf("%d", time.Now().Unix()))
	_, err = client.CreateBucket(&s3.CreateBucketInput{
		Bucket: aws.String(dir),
	})
	if err != nil {
		log.Fatal(err)
	}

	// Export logs to S3
	ag.storageMutex.Lock()
	defer ag.storageMutex.Unlock()

	// Write logs to S3
	file, err := os.Create(filepath.Join(dir, "log.txt.gz"))
	if err != nil {
		log.Fatal(err)
	}
	defer file.Close()

	gzipWriter := gzip.NewWriter(file)
	_, err = gzipWriter.Write([]byte(fmt.Sprintf("%s\n", ag.entries)))
	if err != nil {
		log.Fatal(err)
	}
	gzipWriter.Close()

	// Delete old logs
	ag.rotationChan <- true
}

// Start the log aggregation process
func (ag *LogAggregator) Start() {
	// Start processing logs
	go ag.ProcessLogs()
}

// Stop the log aggregation process
func (ag *LogAggregator) Stop() {
	ag.rotationChan <- true
}

