type File struct {
	ID       string
	Name     string
	Size     int64
	Content  []byte
	Hash     string
	UpdatedAt int64
}

type FileStore struct {
	files map[string]*File
	mutex sync.Mutex
}

func NewFileStore() *FileStore {
	return &FileStore{
		files: make(map[string]*File),
	}
}

func (fs *FileStore) UploadFile(name string, content []byte) error {
	fs.mutex.Lock()
	defer fs.mutex.Unlock()

	if _, exists := fs.files[name]; exists {
		return errors.New("file already exists")
	}

	file := &File{
		ID:       name,
		Name:     name,
		Size:     len(content),
		Content:  content,
		Hash:     hashContent(content),
		UpdatedAt: time.Now().Unix(),
	}

	fs.files[name] = file
	return nil
}

func (fs *FileStore) DownloadFile(name string) ([]byte, error) {
	fs.mutex.Lock()
	defer fs.mutex.Unlock()

	file, exists := fs.files[name]
	if !exists {
		return nil, errors.New("file not found")
	}

	return file.Content, nil
}

func (fs *FileStore) DeleteFile(name string) error {
	fs.mutex.Lock()
	defer fs.mutex.Unlock()

	if _, exists := fs.files[name]; !exists {
		return errors.New("file not found")
	}

	delete(fs.files, name)
	return nil
}

func hashContent(content []byte) string {
	hash := sha256.New()
	hash.Write(content)
	return hex.EncodeToString(hash.Sum(nil))
}

func init() {
	_ = os.MkdirAll("filestore", os.ModePerm)
}

