class LogAnalyzer {
public:
    LogAnalyzer(const std::string& filePath) : filePath(filePath) {}

    void parseLog() {
        std::ifstream logFile(filePath);
        if (!logFile.is_open()) {
            throw std::runtime_error("Cannot open log file");
        }

        std::string line;
        while (std::getline(logFile, line)) {
            if (!line.empty()) {
                // Simple parsing: split by whitespace
                std::vector<std::string> tokens = {};
                size_t pos = 0;
                while (pos < line.length()) {
                    size_t nextSpace = line.find(' ', pos);
                    if (nextSpace == std::string::npos) {
                        nextSpace = line.length();
                    }
                    tokens.push_back(line.substr(pos, nextSpace - pos));
                    pos = nextSpace;
                }
                // Assume first token is severity, second is message
                if (tokens.size() >= 2) {
                    std::string severity = tokens[0];
                    std::string message = tokens[1];
                    // Simple filtering: check severity
                    if (severity == "INFO" || severity == "WARNING" || severity == "ERROR") {
                        entries.push_back({severity, message});
                    }
                }
            }
        }
        logFile.close();
    }

    std::vector<std::pair<std::string, std::string>> filterEntries(const std::string& severity) {
        std::vector<std::pair<std::string, std::string>> filtered;
        for (const auto& entry : entries) {
            if (entry.first == severity) {
                filtered.push_back(entry);
            }
        }
        return filtered;
    }

    void generateReport() {
        std::map<std::string, int> severityCount;
        for (const auto& entry : entries) {
            severityCount[entry.first]++;
        }

        std::cout << "Log Analysis Report:" << std::endl;
        for (const auto& [severity, count] : severityCount) {
            std::cout << "Severity: " << severity << ", Count: " << count << std::endl;
        }
    }

private:
    std::string filePath;
    std::vector<std::pair<std::string, std::string>> entries;
};

