    use std::fs::File;
    use std::io::{Read, Write};
    use std::path::Path;
    use std::error::Error;

    #[derive(Debug)]
    pub struct FileMetadata {
        pub size: usize,
        pub modified: std::time::SystemTime,
    }

    impl FileMetadata {
        pub fn new(size: usize, modified: std::time::SystemTime) -> Self {
            FileMetadata { size, modified }
        }
    }

    pub fn read_file(path: &str) -> Result<String, Box<dyn Error>> {
        let mut file = File::open(path)?;
        let mut contents = String::new();
        file.read_to_string(&mut contents)?;
        Ok(contents)
    }

    pub fn write_file(path: &str, content: &str) -> Result<(), Box<dyn Error>> {
        let mut file = File::create(path)?;
        file.write_all(content.as_bytes())?;
        Ok(())
    }

    pub fn get_metadata(path: &str) -> Result<FileMetadata, Box<dyn Error>> {
        let path = Path::new(path);
        let file = File::open(path)?;
        let stats = file.metadata()?;
        let size = stats.len();
        let modified = stats.modified_time().unwrap_or(std::time::SystemTime::now());
        Ok(FileMetadata::new(size, modified))
    }
}

