type NetworkActivity struct {
	IP           string
	Port         int
	Protocol     string
	BytesSent    int64
	BytesReceived int64
	LastActivity time.Time
}

type Monitor struct {
	activities []NetworkActivity
	connections map[string]*net.TCPConn
	logs        []string
}

func NewMonitor() *Monitor {
	return &Monitor{
		connections: make(map[string]*net.TCPConn),
		activities:  make([]NetworkActivity, 0),
		logs:        make([]string, 0),
	}
}

func (m *Monitor) monitorTraffic() {
	for {
		select {
		case <-time.After(1 * time.Second):
			m.checkConnections()
			m.logActivity()
		}
	}
}

func (m *Monitor) checkConnections() {
	for ip, conn := range m.connections {
		if conn == nil {
			delete(m.connections, ip)
			continue
		}
		// Check if connection is still active
		if !conn.Conned() {
			delete(m.connections, ip)
		}
	}
}

func (m *Monitor) detectIntrusion() {
	// Simple intrusion detection logic
	// In a real scenario, this would involve more complex checks
	for _, activity := range m.activities {
		if activity.BytesSent > 100000000 && activity.BytesReceived > 100000000 {
			m.logActivity()
			return
		}
	}
}

func (m *Monitor) logActivity() {
	// Log activity to file or console
	m.logs = append(m.logs, fmt.Sprintf("Activity: %v", m.activities))
}

func (m *Monitor) monitorTraffic() {
	go m.monitorTraffic()
}

func (m *Monitor) detectIntrusion() {
	go m.detectIntrusion()
}

func (m *Monitor) logActivity() {
	go m.logActivity()
}

func (m *Monitor) AddConnection(ip string, port int, protocol string) {
	conn, err := net.Dial("tcp", fmt.Sprintf("%s:%d", ip, port))
	if err != nil {
		m.logActivity()
		return
	}
	m.connections[ip] = conn
	m.activities = append(m.activities, NetworkActivity{
		IP:           ip,
		Port:         port,
		Protocol:     protocol,
		BytesSent:    0,
		BytesReceived: 0,
		LastActivity: time.Now(),
	})
}

func (m *Monitor) GetActivities() []NetworkActivity {
	return m.activities
}

func (m *Monitor) GetLogs() []string {
	return m.logs
