    cout << "Area: " << myCircle.calculateArea() << endl;
    cout << "Perimeter: " << myCircle.calculatePerimeter() << endl;
    return 0;
}

package main

import "fmt"

func calculateSum(inputSlice []int) int {
    sum := 0
    for _, num := range inputSlice {
        sum += num
    }
    return sum
}

func main() {
    fmt.Println(calculateSum([]int{1, 2, 3}))       // Output: 6
    fmt.Println(calculateSum([]int{}))             // Output: 0
    fmt.Println(calculateSum([]int{5, -3, 7}))      // Output: 9
}

class ShoppingCart {
    var items: MutableList<Item> = mutableListOf()

    fun addItem(item: Item) {
        items.add(item)
    }

    fun calculateTotalPrice(): Double {
        return items.sumBy { it.price }
    }
}

class Stack {
  constructor() {
    this.items = [];
  }

  push(item) {
    this.items.push(item);
  }

  pop() {
    return this.items.pop();
  }

  peek() {
    return this.items[this.items.length - 1];
  }
}
